public class PixelGrid {
    private String[][] grid;

    public PixelGrid(int rows, int cols) {
        grid = new String[rows][cols];
        for (int r = 0; r < rows; r++) {
            for (int c = 0; c < cols; c++) {
                grid[r][c] = "white";
            }
        }
    }

    public void setPixel(int row, int col, String color) {
        grid[row][col] = color;
    }

    public int countColor(String color) {
        int count = 0;
        for (int r = 0; r < grid.length; r++) {
            for (int c = 0; c < grid[0].length; c++) {
                if (grid[r][c].equals(color)) {
                    count++;
                }
            }
        }
        return count;
    }

    public void replaceColor(String oldColor, String newColor) {
        for (int r = 0; r < grid.length; r++) {
            for (int c = 0; c < grid[0].length; c++) {
                if (grid[r][c].equals(oldColor)) {
                    grid[r][c] = newColor;
                }
            }
        }
    }
}

