public class Garden {
    private int[][] plot;

    public Garden(int rows, int cols) {
        plot = new int[rows][cols];
    }

    public int getHeight(int r, int c) { return plot[r][c]; }

    public void setHeight(int r, int c, int h) { plot[r][c] = h; }

    public int tallestInRow(int row) {
        int max = 0;
        for (int c = 0; c < plot[row].length; c++) {
            if (plot[row][c] > max) {
                max = plot[row][c];
            }
        }
        return max;
    }

    public int countTallPlants(int threshold) {
        int count = 0;
        for (int r = 0; r < plot.length; r++) {
            for (int c = 0; c < plot[r].length; c++) {
                if (plot[r][c] > threshold) {
                    count++;
                }
            }
        }
        return count;
    }
}

