import java.util.ArrayList;

public class Donation {
    private String title;
    private int copies;
    public Donation(String t, int c) { title = t; copies = c; }
    public String getTitle() { return title; }
    public int getCopies() { return copies; }
}

class DonationDrive {
    private ArrayList<Donation> donations;

    public DonationDrive() {
        donations = new ArrayList<Donation>();
    }

    public boolean addDonation(Donation d) {
        for (int i = 0; i < donations.size(); i++) {
            if (donations.get(i).getTitle().equals(d.getTitle())) {
                return false;
            }
        }
        donations.add(d);
        return true;
    }

    public int totalPopularCopies(ArrayList<Donation> incoming, int minCopies) {
        for (int i = 0; i < incoming.size(); i++) {
            addDonation(incoming.get(i));
        }
        int total = 0;
        for (int i = 0; i < donations.size(); i++) {
            if (donations.get(i).getCopies() >= minCopies) {
                total += donations.get(i).getCopies();
            }
        }
        return total;
    }
}

