import java.util.ArrayList;

class Hike {
    private String name;
    private double miles;
    public Hike(String n, double m) { name = n; miles = m; }
    public String getName() { return name; }
    public double getMiles() { return miles; }
}

class HikingPlan {
    private ArrayList<Hike> hikes;
    private double maxMiles;

    public HikingPlan(double max) {
        hikes = new ArrayList<Hike>();
        maxMiles = max;
    }

    public boolean addHike(Hike h) {
        double total = 0.0;
        for (Hike x : hikes) {
            total += x.getMiles();
        }
        if (total + h.getMiles() <= maxMiles) {
            hikes.add(h);
            return true;
        }
        return false;
    }

    public int planFromOptions(ArrayList<Hike> options) {
        int count = 0;
        for (Hike h : options) {
            if (addHike(h)) {
                count++;
            }
        }
        return count;
    }

    public int size() { return hikes.size(); }
}

