public class LibraryBook {
    private String title;
    private String author;
    private int timesCheckedOut;
    private boolean isCheckedOut;

    public LibraryBook(String title, String author, int timesCheckedOut) {
        this.title = title;
        this.author = author;
        this.timesCheckedOut = timesCheckedOut;
        this.isCheckedOut = false;
    }

    public LibraryBook(String title, String author) {
        this.title = title;
        this.author = author;
        this.timesCheckedOut = 0;
        this.isCheckedOut = false;
    }

    public void checkOut() {
        if (!isCheckedOut) {
            isCheckedOut = true;
            timesCheckedOut++;
        }
    }

    public String getInfo() {
        String status;
        if (isCheckedOut) {
            status = "currently checked out";
        } else {
            status = "available";
        }
        return title + " by " + author + " (" + status + "), checkouts: " + timesCheckedOut;
    }
}

