        int space = rest.indexOf(" ");
        while (space != -1) {
            String w = rest.substring(0, space);
            if (containsBanned(w)) {
                count++;
            }
            rest = rest.substring(space + 1);
            space = rest.indexOf(" ");
        }
        if (containsBanned(rest)) {
            count++;
        }
        return count;
    }
}
